"use strict";class LogSettings{static async setLogLevel(){try{const e=apex.item("P9010_LOG_LEVEL").getValue();await apex.server.process("SET_LOG_LEVEL",{x01:e});apex.message.showPageSuccess("Log level updated.")}catch(e){apex.message.showErrors([{type:"error",location:"page",message:"Failed to update log level. Please try again.",unsafe:!1}])}}}